import{c as a,Q as s,j as i,m as t}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"@muhaven/mcp — troubleshooting","description":"Symptom → fix for the most common MCP install and auth issues.","frontmatter":{"title":"@muhaven/mcp — troubleshooting","description":"Symptom → fix for the most common MCP install and auth issues."},"headers":[],"relativePath":"mcp/troubleshooting.md","filePath":"mcp/troubleshooting.md","lastUpdated":1778983454000}'),o={name:"mcp/troubleshooting.md"};function n(l,e,r,h,d,p){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="mcp-troubleshooting" tabindex="-1">MCP troubleshooting <a class="header-anchor" href="#mcp-troubleshooting" aria-label="Permalink to &quot;MCP troubleshooting&quot;">​</a></h1><p>A symptom-first reference. Start by running <code>muhaven-broker doctor</code> — it surfaces 80% of issues in one line.</p><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><h3 id="command-not-found-muhaven-broker" tabindex="-1">&quot;Command not found: muhaven-broker&quot; <a class="header-anchor" href="#command-not-found-muhaven-broker" aria-label="Permalink to &quot;&quot;Command not found: muhaven-broker&quot;&quot;">​</a></h3><p>You installed locally (not globally). Either:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @muhaven/mcp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # makes both bins global</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or use the local path</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./node_modules/.bin/muhaven-broker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h3 id="eacces-permission-denied-on-linux-macos" tabindex="-1">&quot;EACCES: permission denied&quot; on Linux/macOS <a class="header-anchor" href="#eacces-permission-denied-on-linux-macos" aria-label="Permalink to &quot;&quot;EACCES: permission denied&quot; on Linux/macOS&quot;">​</a></h3><p>Either:</p><ul><li><code>sudo npm install -g @muhaven/mcp</code> (root-installed global), or</li><li>Use a Node version manager (nvm / fnm / volta) so <code>npm install -g</code> doesn&#39;t need root.</li></ul><h3 id="cannot-find-module-napi-rs-keyring" tabindex="-1">&quot;Cannot find module &#39;@napi-rs/keyring&#39;&quot; <a class="header-anchor" href="#cannot-find-module-napi-rs-keyring" aria-label="Permalink to &quot;&quot;Cannot find module &#39;@napi-rs/keyring&#39;&quot;&quot;">​</a></h3><p>The keyring native module didn&#39;t install for your platform. Two paths:</p><ol><li>Reinstall: <code>npm install -g @muhaven/mcp --force</code> (forces the native postinstall).</li><li>Use the file fallback: <code>export MUHAVEN_KEYRING=file</code> and restart the broker.</li></ol><h3 id="windows-muhaven-mcp-cmd-not-found-by-claude-desktop" tabindex="-1">Windows: &quot;muhaven-mcp.cmd not found by Claude Desktop&quot; <a class="header-anchor" href="#windows-muhaven-mcp-cmd-not-found-by-claude-desktop" aria-label="Permalink to &quot;Windows: &quot;muhaven-mcp.cmd not found by Claude Desktop&quot;&quot;">​</a></h3><p>Claude Desktop on Windows sometimes runs in a sandbox that doesn&#39;t see your user PATH. Use the absolute path in <code>claude_desktop_config.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;muhaven&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;C:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Users</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">you</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">AppData</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Roaming</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">muhaven-mcp.cmd&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><h3 id="device-code-flow-opens-browser-but-link-page-is-blank" tabindex="-1">&quot;Device-code flow opens browser but <code>/link</code> page is blank&quot; <a class="header-anchor" href="#device-code-flow-opens-browser-but-link-page-is-blank" aria-label="Permalink to &quot;&quot;Device-code flow opens browser but \`/link\` page is blank&quot;&quot;">​</a></h3><p>Two possibilities:</p><ol><li><strong>The backend isn&#39;t reachable.</strong> Check <code>https://api.muhaven.app/health</code> returns <code>{&quot;status&quot;:&quot;ok&quot;}</code>.</li><li><strong>You&#39;re not signed into the dashboard.</strong> Open <code>https://muhaven.app</code> first, sign in with your passkey, then re-run <code>muhaven-broker login</code>.</li></ol><h3 id="authorized-in-the-browser-but-broker-still-says-awaiting-authorization" tabindex="-1">&quot;Authorized in the browser, but broker still says <code>awaiting authorization</code>&quot; <a class="header-anchor" href="#authorized-in-the-browser-but-broker-still-says-awaiting-authorization" aria-label="Permalink to &quot;&quot;Authorized in the browser, but broker still says \`awaiting authorization\`&quot;&quot;">​</a></h3><p>The broker polls the backend for completion. Give it a moment. If it still says awaiting:</p><ul><li>Check the broker terminal for an error message.</li><li>The device code may have expired (5-minute TTL). Re-run <code>muhaven-broker login</code>.</li></ul><h3 id="_401-unauthorized-on-every-tool-call" tabindex="-1">&quot;<code>401 UNAUTHORIZED</code> on every tool call&quot; <a class="header-anchor" href="#_401-unauthorized-on-every-tool-call" aria-label="Permalink to &quot;&quot;\`401 UNAUTHORIZED\` on every tool call&quot;&quot;">​</a></h3><p>Your JWT expired (default 1h). Run <code>muhaven-broker login</code> again.</p><p>If it persists right after login, check <code>muhaven-broker doctor</code> — the <code>keystore</code> line tells you where the JWT was actually stored. On WSL2 / devcontainer, you may need <code>export MUHAVEN_KEYRING=file</code>.</p><h3 id="_403-not-approved-issuer-on-an-issuer-tool" tabindex="-1">&quot;<code>403 NOT_APPROVED_ISSUER</code> on an issuer tool&quot; <a class="header-anchor" href="#_403-not-approved-issuer-on-an-issuer-tool" aria-label="Permalink to &quot;&quot;\`403 NOT_APPROVED_ISSUER\` on an issuer tool&quot;&quot;">​</a></h3><p>Either:</p><ul><li>You&#39;re signed in with your investor passkey. Issuer tools require your <strong>issuer&#39;s MuHaven wallet</strong> — see <a href="/get-started/investor-vs-issuer">Investor vs issuer</a>.</li><li>Your issuer status isn&#39;t <code>approved</code>. Visit <code>/apply-issuer</code> on the dashboard.</li></ul><h3 id="_423-paused-on-every-propose-call" tabindex="-1">&quot;<code>423 PAUSED</code> on every propose call&quot; <a class="header-anchor" href="#_423-paused-on-every-propose-call" aria-label="Permalink to &quot;&quot;\`423 PAUSED\` on every propose call&quot;&quot;">​</a></h3><p>Your agent is paused. Sign in to the dashboard at <code>muhaven.app/agent</code> and resume. The resume ceremony involves a WebAuthn passkey signature that MCP can&#39;t drive (no DOM).</p><h2 id="transport" tabindex="-1">Transport <a class="header-anchor" href="#transport" aria-label="Permalink to &quot;Transport&quot;">​</a></h2><h3 id="econnrefused-on-tmp-muhaven-broker-sock" tabindex="-1">&quot;ECONNREFUSED on <code>/tmp/muhaven-broker.sock</code>&quot; <a class="header-anchor" href="#econnrefused-on-tmp-muhaven-broker-sock" aria-label="Permalink to &quot;&quot;ECONNREFUSED on \`/tmp/muhaven-broker.sock\`&quot;&quot;">​</a></h3><p>The broker isn&#39;t running. In a separate terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span></span></code></pre></div><p>If the broker terminal says it&#39;s listening but you still get <code>ECONNREFUSED</code>, you may have a socket path mismatch. Set explicitly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Broker terminal</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MUHAVEN_BROKER_SOCKET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/tmp/muhaven-broker.sock</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># MCP server (host config)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;env&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;MUHAVEN_BROKER_SOCKET&quot;:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/tmp/muhaven-broker.sock&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> }</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> }</span></span></code></pre></div><h3 id="parse-error-from-broker" tabindex="-1">&quot;PARSE_ERROR from broker&quot; <a class="header-anchor" href="#parse-error-from-broker" aria-label="Permalink to &quot;&quot;PARSE_ERROR from broker&quot;&quot;">​</a></h3><p>The MCP server sent malformed JSON. This is usually a version mismatch — your <code>muhaven-mcp</code> and <code>muhaven-broker</code> are from different <code>@muhaven/mcp</code> versions. Reinstall:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @muhaven/mcp@latest</span></span></code></pre></div><p>Both bins ship from the same package; updating it updates both.</p><h3 id="stuck-handshake-hello-not-responding" tabindex="-1">&quot;Stuck handshake (<code>hello</code> not responding)&quot; <a class="header-anchor" href="#stuck-handshake-hello-not-responding" aria-label="Permalink to &quot;&quot;Stuck handshake (\`hello\` not responding)&quot;&quot;">​</a></h3><p>The broker is hung. SIGTERM it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or in the broker terminal: Ctrl-C</span></span></code></pre></div><p>Then restart. If it hangs again on startup, check <code>~/.muhaven/</code> for a stale lock file and remove it.</p><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><h3 id="mcp-server-exits-immediately-on-host-start" tabindex="-1">&quot;MCP server exits immediately on host start&quot; <a class="header-anchor" href="#mcp-server-exits-immediately-on-host-start" aria-label="Permalink to &quot;&quot;MCP server exits immediately on host start&quot;&quot;">​</a></h3><p>Pre-2026-05-10 versions of <code>@muhaven/mcp</code> had a known bin-lifecycle bug where <code>bin/*.cjs</code> would <code>process.exit(0)</code> before the STDIO transport could keep the event loop alive. Symptom: the host says the MCP server exited code 0 within seconds of spawn.</p><p>Fix: update to <code>@muhaven/mcp@0.1.2</code> or later. The bug is fixed in the upgrade.</p><h3 id="tool-descriptions-changed-→-server-exits-with-code-70" tabindex="-1">&quot;Tool descriptions changed → server exits with code 70&quot; <a class="header-anchor" href="#tool-descriptions-changed-→-server-exits-with-code-70" aria-label="Permalink to &quot;&quot;Tool descriptions changed → server exits with code 70&quot;&quot;">​</a></h3><p><code>tool-hashes.json</code> SHA-256 verification fired and detected drift. This is intentional — the description is part of the security contract.</p><p>If you legitimately updated <code>@muhaven/mcp</code> and want to accept the new hashes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/@muhaven/mcp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify-tool-hashes</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # re-pin hashes from current descriptions</span></span></code></pre></div><p>You should only run this if you trust the new descriptions (e.g., you intentionally upgraded). On a &quot;wait, I didn&#39;t update?&quot; failure, investigate before re-pinning.</p><h2 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h2><h3 id="llm-refuses-to-call-a-tool-that-should-exist" tabindex="-1">&quot;LLM refuses to call a tool that should exist&quot; <a class="header-anchor" href="#llm-refuses-to-call-a-tool-that-should-exist" aria-label="Permalink to &quot;&quot;LLM refuses to call a tool that should exist&quot;&quot;">​</a></h3><p>Two possibilities:</p><ul><li><strong>Read-only mode is on.</strong> Check the broker terminal for <code>READ-ONLY MODE</code> banner. To allow propose tools, restart without <code>MUHAVEN_READ_ONLY=true</code>.</li><li><strong>Tier-gated and you&#39;re paused.</strong> Most propose tools require unpause first.</li></ul><h3 id="llm-auto-submits-a-buy-i-didn-t-expect" tabindex="-1">&quot;LLM auto-submits a buy I didn&#39;t expect&quot; <a class="header-anchor" href="#llm-auto-submits-a-buy-i-didn-t-expect" aria-label="Permalink to &quot;&quot;LLM auto-submits a buy I didn&#39;t expect&quot;&quot;">​</a></h3><p>This shouldn&#39;t happen. Position tools return descriptors only; they never auto-submit. If you see an apparent auto-submit:</p><ol><li>Check your dashboard audit log at <code>/agent → Audit</code>. If there&#39;s a <code>permit_granted</code> row, the action did settle on a dashboard surface (not from MCP directly).</li><li>If the tool call output included an <code>audit_id</code>, that&#39;s a <em>propose-time</em> audit row (not a commit). Commit requires a dashboard ConfirmModal step.</li></ol><p>File an issue if you can reproduce auto-submission from MCP itself — it would be a security bug.</p><h3 id="distribute-yield-says-my-token-has-zero-holders" tabindex="-1">&quot;Distribute yield says my token has zero holders&quot; <a class="header-anchor" href="#distribute-yield-says-my-token-has-zero-holders" aria-label="Permalink to &quot;&quot;Distribute yield says my token has zero holders&quot;&quot;">​</a></h3><p>The <code>InvestorRegistry</code> is read at propose time. If you added KYC entries recently, the indexer may not have caught up. Wait and re-propose.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/mcp/install">Install</a> — full install walkthrough.</li><li><a href="/mcp/first-chat">First chat</a> — verify your install end-to-end.</li><li><a href="/mcp/broker">Broker daemon</a> — what the broker does and how.</li></ul>`,65)])])}const k=a(o,[["render",n]]);export{c as __pageData,k as default};
